import React, { useState, useEffect } from 'react';
import './InspectorPanel.css';
import { X, Type, Palette, Layout, Box, Move3D, Settings, ChevronDown, ChevronUp, Trash2 } from 'lucide-react';

interface ElementInfo {
  tagName: string;
  textContent: string;
  className: string;
  id: string;
  styles: {
    color: string;
    backgroundColor: string;
    fontSize: string;
    fontWeight: string;
    margin: string;
    padding: string;
    borderRadius: string;
    width: string;
    height: string;
  };
  innerHTML: string;
}

interface InspectorPanelProps {
  isOpen: boolean;
  selectedElement: ElementInfo | null;
  onClose: () => void;
  onUpdateElement?: (updates: any) => void;
}

type Section = 'layout' | 'typography' | 'appearance';

const InspectorPanel: React.FC<InspectorPanelProps> = ({
  isOpen,
  selectedElement,
  onClose,
  onUpdateElement
}) => {
  // Accordion open states
  const [openSections, setOpenSections] = useState<Record<Section, boolean>>({
    layout: true,
    typography: false,
    appearance: false
  });
  const [editedContent, setEditedContent] = useState('');
  const [editedStyles, setEditedStyles] = useState<any>({});

  useEffect(() => {
    if (selectedElement) {
      setEditedContent(selectedElement.textContent || '');
      setEditedStyles({
        color: selectedElement.styles.color,
        backgroundColor: selectedElement.styles.backgroundColor,
        fontSize: selectedElement.styles.fontSize,
        fontWeight: selectedElement.styles.fontWeight,
        margin: selectedElement.styles.margin,
        padding: selectedElement.styles.padding,
        borderRadius: selectedElement.styles.borderRadius,
        width: selectedElement.styles.width,
        height: selectedElement.styles.height,
      });
    }
  }, [selectedElement]);

  const handleAccordionToggle = (section: Section) => {
    setOpenSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  const handleContentChange = (value: string) => {
    setEditedContent(value);
    onUpdateElement && onUpdateElement({ textContent: value });
  };

  const handleStyleChange = (property: string, value: string) => {
    const newStyles = { ...editedStyles, [property]: value };
    setEditedStyles(newStyles);
    onUpdateElement && onUpdateElement({ styles: { [property]: value } });
  };

  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : null;
  };

  const rgbToHex = (rgb: string) => {
    const match = rgb.match(/\d+/g);
    if (!match) return '#000000';
    return '#' + ((1 << 24) + (parseInt(match[0]) << 16) + (parseInt(match[1]) << 8) + parseInt(match[2])).toString(16).slice(1);
  };

  if (!isOpen) return null;

  return (
    <div className="inspector-panel">
      {/* Header */}
      <div className="inspector-header">
        <div className="inspector-title">
          <Settings size={18} />
          <span>Inspector</span>
        </div>
        <button className="close-inspector" onClick={onClose}>
          <X size={18} />
        </button>
      </div>

      {/* Content */}
      <div className="inspector-content">
        {selectedElement ? (
          <>
            {/* Element Info */}
            <div className="element-info">
              <div className="element-tag">
                <span className="tag-name">&lt;{selectedElement.tagName}&gt;</span>
                {selectedElement.className && (
                  <span className="class-name">.{selectedElement.className}</span>
                )}
              </div>
            </div>

            {/* Accordion: Layout */}
            <div className={`accordion-section${openSections.layout ? ' open' : ''}`}> 
              <button className="accordion-header" onClick={() => handleAccordionToggle('layout')}>
                <Layout size={20} />
                <span>Layout</span>
                {openSections.layout ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
              </button>
              {openSections.layout && (
                <div className="accordion-content">
                  <div className="property-group">
                    <label>Dimensions</label>
                    <div className="dimension-row">
                      <div className="dimension-input">
                        <span>W</span>
                        <input type="number" value={parseFloat(editedStyles.width) || ''} onChange={e => handleStyleChange('width', e.target.value)} />
                        <span className="unit">px</span>
                      </div>
                      <div className="dimension-input">
                        <span>H</span>
                        <input type="number" value={parseFloat(editedStyles.height) || ''} onChange={e => handleStyleChange('height', e.target.value)} />
                        <span className="unit">px</span>
                      </div>
                    </div>
                  </div>
                  <div className="property-group">
                    <label>Margin</label>
                    <div className="spacing-grid">
                      <input type="number" value={0} readOnly />
                      <input type="number" value={0} readOnly />
                      <input type="number" value={0} readOnly />
                      <input type="number" value={0} readOnly />
                    </div>
                  </div>
                  <div className="property-group">
                    <label>Padding</label>
                    <div className="spacing-grid">
                      <input type="number" value={16} readOnly />
                      <input type="number" value={16} readOnly />
                      <input type="number" value={4} readOnly />
                      <input type="number" value={4} readOnly />
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Accordion: Typography */}
            <div className={`accordion-section${openSections.typography ? ' open' : ''}`}> 
              <button className="accordion-header" onClick={() => handleAccordionToggle('typography')}>
                <Type size={20} />
                <span>Typography</span>
                {openSections.typography ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
              </button>
              {openSections.typography && (
                <div className="accordion-content">
                  <div className="property-group">
                    <label>Placeholder</label>
                    <input type="text" value={editedContent} onChange={e => handleContentChange(e.target.value)} placeholder="Enter your email" />
                  </div>
                  <div className="property-group">
                    <label>Text Alignment</label>
                    <div className="alignment-row">
                      <button className="align-btn"> <span style={{fontFamily:'monospace'}}>≡</span> </button>
                      <button className="align-btn"> <span style={{fontFamily:'monospace'}}>≡</span> </button>
                      <button className="align-btn"> <span style={{fontFamily:'monospace'}}>≡</span> </button>
                    </div>
                  </div>
                  <div className="property-group">
                    <label>Font Family</label>
                    <select>
                      <option>Default</option>
                    </select>
                  </div>
                  <div className="property-group">
                    <label>Font Weight</label>
                    <select>
                      <option>Regular</option>
                    </select>
                  </div>
                  <div className="property-group">
                    <label>Font Style</label>
                    <div className="font-style-row">
                      <button className="font-style-btn">_</button>
                      <button className="font-style-btn">B</button>
                      <button className="font-style-btn">I</button>
                    </div>
                  </div>
                  <div className="property-group">
                    <label>Font Size</label>
                    <div className="font-size-row">
                      <select>
                        <option>SM</option>
                      </select>
                      <input type="number" value={14} readOnly />
                    </div>
                  </div>
                  <div className="property-group">
                    <label>Line Height</label>
                    <div className="line-height-row">
                      <select>
                        <option>Custom</option>
                      </select>
                      <input type="number" value={1.5} readOnly />
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Accordion: Appearance */}
            <div className={`accordion-section${openSections.appearance ? ' open' : ''}`}> 
              <button className="accordion-header" onClick={() => handleAccordionToggle('appearance')}>
                <Palette size={20} />
                <span>Appearance</span>
                {openSections.appearance ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
              </button>
              {openSections.appearance && (
                <div className="accordion-content">
                  <div className="property-group">
                    <label>Text Color</label>
                    <input type="text" value={editedStyles.color} readOnly />
                  </div>
                  <div className="property-group">
                    <label>Background Color</label>
                    <input type="text" value={editedStyles.backgroundColor} readOnly />
                  </div>
                  <div className="property-group">
                    <label>Stroke</label>
                    <input type="text" value={2} readOnly />
                  </div>
                  <div className="property-group">
                    <label>Radius</label>
                    <input type="text" value={14} readOnly />
                  </div>
                  <div className="property-group">
                    <label>Shadow</label>
                    <select>
                      <option>Small</option>
                    </select>
                  </div>
                </div>
              )}
            </div>

            {/* Delete Element Button */}
            <button className="delete-element-btn">
              <Trash2 size={20} /> Delete Element
            </button>
          </>
        ) : (
          <div className="no-selection">
            <div className="no-selection-icon">
              <Move3D size={32} />
            </div>
            <h3>No element selected</h3>
            <p>Select an element to edit its properties.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default InspectorPanel;
